parameters.text:
=Decision Request Data:
- Decision ID: {{ $json.decisionId }}
- Type: {{ $json.decisionType }}
- Amount: ${{ $json.requestedAmount }}
- Department: {{ $json.department }}
- Requestor: {{ $json.requestor }}
- Justification: {{ $json.justification }}
- Timestamp: {{ $json.timestamp }}

=🚨 *HIGH RISK DECISION ALERT*

*Decision ID:* {{ $json.output.decisionId || "N/A" }}
*Risk Level:* {{ $json.output.overallRiskLevel }}
*Risk Score:* {{ $json.output.riskScore }}/100
*Approval Status:* {{ $json.output.approvalStatus }}
*Compliance Status:* {{ $json.output.complianceStatus }}

*Governance Decision:*
{{ $json.output.governanceDecision }}

*Required Actions:*
{{ $json.output.requiredActions ? $json.output.requiredActions.map((a, i) => `${i+1}. ${a}`).join("\n") : "None" }}

*Escalation Required:* {{ $json.output.escalationRequired ? "YES" : "NO" }}

_Timestamp: {{ $now.toFormat("yyyy-MM-dd HH:mm:ss") }}_
